mapper.insert:
INSERT INTO monitor_event_agg_hour (
  project_id, bucket_start, event_type, total_count, error_count, page_view_count
) VALUES (
  #{projectId}, #{bucketStart}, #{eventType}, #{totalCount}, #{errorCount}, #{pageViewCount}
)
ON DUPLICATE KEY UPDATE
  total_count = total_count + VALUES(total_count),
  error_count = error_count + VALUES(error_count),
  page_view_count = page_view_count + VALUES(page_view_count)

INSERT INTO monitor_event_agg_day (
  project_id, event_date, event_type, total_count, error_count, page_view_count
) VALUES (
  #{projectId}, #{eventDate}, #{eventType}, #{totalCount}, #{errorCount}, #{pageViewCount}
)
ON DUPLICATE KEY UPDATE
  total_count = total_count + VALUES(total_count),
  error_count = error_count + VALUES(error_count),
  page_view_count = page_view_count + VALUES(page_view_count)

mapper.select:
SELECT DATE_FORMAT(bucket_start, '%Y-%m-%d %H:00:00') AS bucket,
       SUM(total_count) AS totalCount,
       SUM(error_count) AS errorCount,
       SUM(page_view_count) AS pageViewCount
FROM monitor_event_agg_hour
WHERE project_id = #{projectId}
  AND bucket_start  >=  #{startTime}
  AND bucket_start  <=  #{endTime}
GROUP BY bucket_start
ORDER BY bucket_start ASC

SELECT DATE_FORMAT(event_date, '%Y-%m-%d') AS bucket,
       SUM(total_count) AS totalCount,
       SUM(error_count) AS errorCount,
       SUM(page_view_count) AS pageViewCount
FROM monitor_event_agg_day
WHERE project_id = #{projectId}
  AND event_date  >=  #{startDate}
  AND event_date  <=  #{endDate}
GROUP BY event_date
ORDER BY event_date ASC
